// All-in-one: Validate Slack signature → Check allowlist → Route action → Call GitHub API
const crypto = require('crypto');
const https = require('https');
const { URLSearchParams } = require('url');

// --- Helper: HTTPS request ---
function httpsRequest(url, method, hdrs, body) {
  return new Promise((resolve, reject) => {
    const urlObj = new URL(url);
    const bodyStr = body ? JSON.stringify(body) : null;
    const options = {
      hostname: urlObj.hostname,
      path: urlObj.pathname + urlObj.search,
      method,
      headers: {
        ...hdrs,
        ...(bodyStr ? { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(bodyStr) } : {})
      }
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => resolve({ status: res.statusCode, data }));
    });
    req.on('error', reject);
    if (bodyStr) req.write(bodyStr);
    req.end();
  });
}

// --- 1. Validate Slack Signature ---
const headers = $input.first().json.headers;
const rawBody = Buffer.from($input.first().binary.data.data, 'base64').toString('utf-8');
const signature = headers['x-slack-signature'];
const timestamp = headers['x-slack-request-timestamp'];
const signingSecret = $env.SLACK_SIGNING_SECRET;

if (!signingSecret) {
  return [{ json: { responseText: 'Error: SLACK_SIGNING_SECRET not configured' } }];
}

const now = Math.floor(Date.now() / 1000);
if (Math.abs(now - parseInt(timestamp, 10)) > 300) {
  return [{ json: { responseText: 'Error: Request timestamp too old' } }];
}

const sigBasestring = `v0:${timestamp}:${rawBody}`;
const expected = 'v0=' + crypto.createHmac('sha256', signingSecret).update(sigBasestring).digest('hex');
if (!crypto.timingSafeEqual(Buffer.from(signature || ''), Buffer.from(expected))) {
  return [{ json: { responseText: 'Error: Invalid Slack signature' } }];
}

// --- 2. Parse Payload ---
const payload = JSON.parse(decodeURIComponent(rawBody.replace('payload=', '')));
const action = payload.actions?.[0] || {};
const actionId = action.action_id || '';
const actionValue = action.value || '';
const userId = payload.user?.id || '';

// --- 3. Check Allowlist ---
const adminUsers = ($env.SLACK_ADMIN_USERS || '').split(',').map(s => s.trim()).filter(Boolean);
const allowedUsers = ($env.SLACK_ALLOWED_USERS || '').split(',').map(s => s.trim()).filter(Boolean);

let tier = 'readonly';
if (adminUsers.length > 0 && adminUsers.includes(userId)) {
  tier = 'admin';
} else if (adminUsers.length === 0 && allowedUsers.length > 0 && allowedUsers.includes(userId)) {
  tier = 'admin';
} else if (allowedUsers.includes(userId)) {
  tier = 'allowed';
}

if (tier === 'readonly') {
  if (allowedUsers.length > 0) {
    return [{ json: { responseText: 'Error: Not authorized' } }];
  }
  tier = 'admin';
}

const adminOnlyPrefixes = ['scan_backlog:', 'trigger_implement:', 'close_abandoned_prs'];
const isAdminAction = adminOnlyPrefixes.some(p => actionId.startsWith(p));
if (isAdminAction && tier !== 'admin') {
  return [{ json: { responseText: 'Error: Admin action requires admin tier' } }];
}

// --- 4. Route & Execute ---
const githubToken = $env.GITHUB_PAT;
const repo = 'stoa-platform/stoa';
const ghHeaders = {
  'Accept': 'application/vnd.github.v3+json',
  'Authorization': `token ${githubToken}`,
  'User-Agent': 'n8n-stoa-ai-factory'
};

let responseText = 'Unknown action — ignored.';

try {
  if (actionId.startsWith('approve_ticket:')) {
    await httpsRequest(
      `https://api.github.com/repos/${repo}/issues/${actionValue}/comments`,
      'POST', ghHeaders, { body: '/go' }
    );
    responseText = `✅ Approved ticket — posted /go on issue #${actionValue}`;

  } else if (actionId.startsWith('approve_plan:')) {
    await httpsRequest(
      `https://api.github.com/repos/${repo}/issues/${actionValue}/comments`,
      'POST', ghHeaders, { body: '/go-plan' }
    );
    responseText = `✅ Approved plan — posted /go-plan on issue #${actionValue}`;

  } else if (actionId.startsWith('merge_pr:')) {
    await httpsRequest(
      `https://api.github.com/repos/${repo}/pulls/${actionValue}/merge`,
      'PUT', ghHeaders, { merge_method: 'squash' }
    );
    responseText = `✅ Merged PR #${actionValue} (squash)`;

  } else if (actionId === 'close_abandoned_prs') {
    // List open PRs labelled 'abandoned'
    const listRes = await httpsRequest(
      `https://api.github.com/repos/${repo}/issues?labels=abandoned&state=open&per_page=50`,
      'GET', ghHeaders
    );
    const issues = JSON.parse(listRes.data).filter(i => i.pull_request);
    let closed = 0;
    for (const issue of issues) {
      await httpsRequest(
        `https://api.github.com/repos/${repo}/issues/${issue.number}/comments`,
        'POST', ghHeaders, { body: 'Auto-closed by PR Hygiene pipeline.' }
      );
      await httpsRequest(
        `https://api.github.com/repos/${repo}/issues/${issue.number}`,
        'PATCH', ghHeaders, { state: 'closed' }
      );
      closed++;
    }
    responseText = `✅ Closed ${closed} abandoned PR(s).`;
  }
} catch (err) {
  responseText = `❌ GitHub API error: ${err.message}`;
}

return [{ json: { responseText } }];
